const POLICY = "You are fixing Report Manager documentation pages (recently de-iframed into self-contained HTML). For each file use the Read tool, then the Edit tool to make SURGICAL fixes ONLY inside the <main class=\"doc-main\"> ... </main> region.\nNEVER modify: <head>, <header class=\"doc-top\">, the sidebar <div class=\"doc-nav-wrap\"> / <nav class=\"doc-nav\">, the <nav class=\"doc-crumb\"> breadcrumb, or the <footer class=\"doc-foot\">. Preserve ALL content, links, images, IDs, anchors, and HTML validity. Change ONLY what the per-file instructions specify (plus any blatant additional spelling error in the same prose). Do not reformat or re-indent untouched markup.\n\nFIX TYPES:\n1) TYPOS: correct each listed misspelling where it appears in PROSE / visible text. Use whole-word replacement. SKIP occurrences inside code, Pascal identifiers, unit/file names, property names, or URLs.\n2) LINKS (given as \"href :: recommendation\"):\n   - \"switch to https\": change the scheme http:// to https:// in the href (and in the visible anchor text too if the text is that same URL). Never change http://localhost examples.\n   - \"remove\" / host \"is gone\" / \"discontinued\" / \"dead\": remove the hyperlink but KEEP its visible text as plain text (unwrap the <a> ... </a>). If the visible text is itself only the dead URL and the sentence/list-item then makes no sense, remove that whole list-item/sentence. Prefer the smallest sensible change.\n   - borland.com repoint: Delphi -> https://www.embarcadero.com/products/delphi ; C++Builder -> https://www.embarcadero.com/products/cbuilder ; Borland Developer Network / BDN articles / generic borland -> https://docwiki.embarcadero.com . Keep the anchor text.\n3) MOJIBAKE: replace garbled encoding sequences with the intended character from context, e.g. \"Ã‚Â¿\" -> \"¿\", \"Ã±\" -> \"ñ\", \"â€™\" -> \"’\", \"â€œ\" -> \"“\", \"â€\" -> \"”\", \"Ã³\" -> \"ó\". If a sequence is so corrupted you cannot tell the intended text (e.g. a long garbled run), replace it with a sensible plain-text placeholder or remove it, and note it.\n4) OBSOLETE REFS (given as \"[recommendation/kind] snippet\"):\n   - \"reword\": rewrite the passage so it is no longer misleading and reflects CURRENT reality: the Report Manager Designer is a Windows VCL application (NOT Qt/CLX); complex-text shaping/BiDi uses DirectWrite on Windows and ICU + HarfBuzz on Linux; current Windows targets are Windows 10/11 and Windows Server; .NET and .NET Core libraries are current; output drivers are PDF, SVG, HTML, GDI/printer, plain-text/CSV and the native metafile. Do NOT present discontinued things as current (Internet Explorer ActiveX plugin, Kylix, Win98/ME/NT/2000/XP \"all current OS\", \"Boxed product\", Qt-based designer).\n     When the passage lists OLD supported targets worth keeping as history (old Delphi/Kylix versions, BDE / DBExpress drivers, CLX), KEEP them but explicitly LABEL them legacy/historical (e.g. add \"(legacy)\" or \"older versions\"). Keep wording terse.\n   - \"remove\": delete the obsolete mention cleanly (e.g. the Yahoo Groups reference) without leaving a dangling sentence.\n   - \"keep-historical\": leave the mention; you MAY add a short \"legacy\" label if it currently reads as if it were current, otherwise leave it untouched.\nBe conservative and precise. After editing, report exactly what you changed per file.";
const VERIFY_POLICY = "You are an ADVERSARIAL verifier checking edits made to Report Manager documentation pages. For each file use Read and inspect ONLY the <main class=\"doc-main\"> region. Your job is to catch problems, not to be charitable.\nFor each file report:\n - typosRemaining: any of the originally-listed misspellings (or other obvious ones) still present in prose.\n - deadLinksRemaining: any originally-flagged dead/legacy external link still present unfixed (still http:// on a live host, or a still-present dead host). Ignore http://localhost examples.\n - mojibakeRemaining: true if garbled encoding sequences remain.\n - misleadingRemaining: any obsolete claim still presented as CURRENT (IE plugin, Kylix/Qt designer, Win98-XP as current OS, Boxed product) that was supposed to be reworded.\n - breakageOrContentLoss: any broken HTML, removed/duplicated headings, lost images or links, truncated sentences, or edits that leaked outside <main>.\n - verdict: \"pass\" only if ALL the above are empty/false; otherwise \"needs-rework\".\nBe specific (quote the offending text). Do not edit anything.";

const FIX_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    files: { type: 'array', items: {
      type: 'object', additionalProperties: false,
      properties: {
        path: { type: 'string' },
        typosFixed: { type: 'integer' },
        linksFixed: { type: 'integer' },
        obsoleteReworded: { type: 'integer' },
        mojibakeFixed: { type: 'boolean' },
        notes: { type: 'string' },
      },
      required: ['path', 'typosFixed', 'linksFixed', 'obsoleteReworded', 'mojibakeFixed', 'notes'],
    } },
  },
  required: ['files'],
}

const VERIFY_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    files: { type: 'array', items: {
      type: 'object', additionalProperties: false,
      properties: {
        path: { type: 'string' },
        verdict: { type: 'string', enum: ['pass', 'needs-rework'] },
        typosRemaining: { type: 'array', items: { type: 'string' } },
        deadLinksRemaining: { type: 'array', items: { type: 'string' } },
        mojibakeRemaining: { type: 'boolean' },
        misleadingRemaining: { type: 'array', items: { type: 'string' } },
        breakageOrContentLoss: { type: 'array', items: { type: 'string' } },
      },
      required: ['path', 'verdict', 'typosRemaining', 'deadLinksRemaining', 'mojibakeRemaining', 'misleadingRemaining', 'breakageOrContentLoss'],
    } },
  },
  required: ['files'],
}

function fileDirectives(path) {
  const d = FIXDATA[path];
  let s = 'FILE: ' + path + '\n';
  if (d.mojibake) s += '  - MOJIBAKE present: fix garbled sequences to the intended character.\n';
  if (d.typos.length) s += '  - Typos: ' + d.typos.map(t => t[0] + '->' + t[1]).join(', ') + '\n';
  if (d.links.length) s += '  - Links: ' + d.links.map(l => l.href + ' :: ' + l.rec).join('  |  ') + '\n';
  if (d.obsolete.length) s += '  - Obsolete refs: ' + d.obsolete.map(o => '[' + o.rec + '/' + o.kind + '] ' + o.text).join('  |  ') + '\n';
  return s;
}

function fixPrompt(files) {
  return POLICY + '\n\nApply fixes to these ' + files.length + ' files:\n\n' + files.map(fileDirectives).join('\n');
}
function verifyPrompt(files) {
  return VERIFY_POLICY + '\n\nCheck these ' + files.length + ' files (the originally-flagged issues are listed for reference):\n\n' + files.map(fileDirectives).join('\n');
}

const results = await pipeline(
  BATCHES,
  (b) => agent(fixPrompt(b.files), { label: 'fix:' + b.label, phase: 'Fix', schema: FIX_SCHEMA }),
  (fixRes, b) => agent(verifyPrompt(b.files), { label: 'verify:' + b.label, phase: 'Verify', schema: VERIFY_SCHEMA })
    .then(v => ({ batch: b.label, fix: fixRes, verify: v })),
)

const flat = results.filter(Boolean)
const verifyFiles = flat.flatMap(r => (r.verify && r.verify.files) || [])
const fixFiles = flat.flatMap(r => (r.fix && r.fix.files) || [])
const needsRework = verifyFiles.filter(f => f.verdict !== 'pass')
const rollup = {
  batches: flat.length,
  filesFixed: fixFiles.length,
  filesVerified: verifyFiles.length,
  passed: verifyFiles.filter(f => f.verdict === 'pass').length,
  needsRework: needsRework.length,
  totalTyposFixed: fixFiles.reduce((s, f) => s + (f.typosFixed || 0), 0),
  totalLinksFixed: fixFiles.reduce((s, f) => s + (f.linksFixed || 0), 0),
  totalObsoleteReworded: fixFiles.reduce((s, f) => s + (f.obsoleteReworded || 0), 0),
  mojibakeFixed: fixFiles.filter(f => f.mojibakeFixed).length,
}
log('Fixed ' + rollup.filesFixed + ' files; verify pass=' + rollup.passed + ' needs-rework=' + rollup.needsRework)

return { rollup, needsRework, fixFiles, verifyFiles }
